const buffer = await this.helpers.getBinaryDataBuffer(0, 'data');
const summary = JSON.parse(buffer.toString('utf-8'));

const noisy = (summary.top_rules || [])
  .filter(r => r.count >= 50)
  .map(r => `  - ${r.description} (id ${r.rule_id}): ${r.count}`)
  .join('\n') || '  (none above 50)';

const byLevel = Object.entries(summary.by_level || {})
  .map(([lvl, cnt]) => `level ${lvl}: ${cnt}`)
  .join(', ') || 'none';

const critical = (summary.critical_alerts || [])
  .map(c => `  - [L${c.level}] ${c.description} on ${c.agent} @ ${c.timestamp}\n    ${c.full_log.slice(0, 200)}`)
  .join('\n') || '  (none — clean overnight)';

const byAgent = Object.entries(summary.by_agent || {})
  .slice(0, 10)
  .map(([a, c]) => `  - ${a}: ${c}`)
  .join('\n') || '  (none)';

const sca = summary.sca_delta || {};
const failed = (sca.new_failures || [])
  .map(f => `  - [${f.policy}] check ${f.check_id} on ${f.agent}: ${f.title}`)
  .join('\n');
const transitions = (sca.transitions || [])
  .map(t => `  - [${t.policy}] check ${t.check_id} on ${t.agent}: ${t.from} -> ${t.to} (${t.events_today} events)`)
  .join('\n');
const scaSection = (failed || transitions)
  ? `SCA delta (CIS / hardening checks, last 24h, ${sca.total_sca_events || 0} events):\n` +
    (failed ? `\nChecks ending FAILED today:\n${failed}\n` : '') +
    (transitions ? `\nChecks that flipped today:\n${transitions}\n` : '')
  : `SCA delta: 0 failed checks, 0 transitions (${sca.total_sca_events || 0} events). All hardening checks stable.`;

const userPrompt = `Wazuh activity for ${summary.window_since.slice(0,10)} (UTC, ${summary.total_alerts} alerts).\n\nLevel distribution: ${byLevel}\n\nTop rules (>=50 hits):\n${noisy}\n\nBy agent (top 10):\n${byAgent}\n\nCritical alerts (level >=12):\n${critical}\n\n${scaSection}\n\nWrite a concise security digest for a homelab operator. Lead with anything that needs action; bury the routine. For SCA, distinguish real config drift from the recurring \`sshd -T\` scan-resolution artifact (UsePAM / MACs / PermitUserEnvironment on Ubuntu agents) — those are known false-positive flaps, not actionable. Markdown OK. Aim for under 30 lines.`;

return [{ json: {
  total_alerts: summary.total_alerts,
  critical_count: (summary.critical_alerts || []).length,
  sca_failed_count: (sca.new_failures || []).length,
  sca_transitions_count: (sca.transitions || []).length,
  user_prompt: userPrompt,
  window: summary.window_since.slice(0,10),
  top_rules_raw: summary.top_rules || [],
  by_level_raw: summary.by_level || {},
  critical_alerts_raw: summary.critical_alerts || [],
  by_agent_raw: summary.by_agent || {},
}}];

// Extract the assistant text from the Anthropic response and format for
// Telegram. Telegram MarkdownV2 has lots of escapes — for v1 we use plain
// markdown with parseMode=Markdown which is more forgiving.
const resp = $input.first().json;
const text = (resp.content && resp.content[0] && resp.content[0].text) || '(no response)';

const dateLine = `*Francis digest — ${$('Build prompt').item.json.window}*`;
const stats = `_${$('Build prompt').item.json.total_alerts} alerts, ${$('Build prompt').item.json.critical_count} critical_`;

return [{ json: {
  message: `${dateLine}\n${stats}\n\n${text}`,
}}];

// Build verifier request body. Pulls draft digest from Anthropic Claude
// output and raw rule + agent + level breakdown from Build prompt.
const resp = $input.first().json;
const draftText = (resp.content && resp.content[0] && resp.content[0].text) || "";

const bp = $("Build prompt").item.json;
const rules = bp.top_rules_raw || [];
const levels = bp.by_level_raw || {};
const agents = bp.by_agent_raw || {};

const rulesLines = rules
  .map(r => "  rule " + r.rule_id + " (\x27" + r.description + "\x27): " + r.count)
  .join("\n") || "  (none)";
const levelsLine = Object.entries(levels)
  .map(([lvl, cnt]) => "L" + lvl + "=" + cnt)
  .join(", ") || "none";
const agentsLines = Object.entries(agents)
  .sort((a, b) => b[1] - a[1])
  .map(([name, cnt]) => "  " + name + ": " + cnt)
  .join("\n") || "  (none)";

const userMsg = "DIGEST:\n" + draftText + "\n\nRAW DATA:\nLevel distribution: " + levelsLine + "\n\nAll rules by count:\n" + rulesLines + "\n\nAll agents by alert count:\n" + agentsLines;

const system = "You are a verifier checking a security digest against raw alert data. Apply these rules in order:\n\n" +
"1. Any rule at level >= 10 with >= 1 hit in RAW DATA that is not named or grouped explicitly in the DIGEST: FLAG.\n" +
"2. Any rule at level 7-9 with > 10 hits in RAW DATA that is not named or grouped explicitly in the DIGEST: FLAG.\n" +
"3. Any rule at level <= 6 with > 5 hits whose description indicates an auth anomaly (description contains \x27failed login\x27, \x27invalid user\x27, \x27illegal root login\x27, \x27brute force\x27, or \x27non-existent user\x27): FLAG. Examples: rule 5710 \x27Attempt to login using a non-existent user\x27 (L5), rule 2504 \x27Illegal root login\x27, rule 5763 \x27sshd brute force\x27.\n" +
"4. Any per-agent claim in DIGEST (e.g. \x27agent X has Y total alerts\x27) that contradicts the \x27All agents by alert count\x27 block in RAW DATA: FLAG. If the agent total in the DIGEST matches the RAW DATA exactly, DO NOT flag.\n" +
"5. Any other factual contradiction between DIGEST and RAW DATA: FLAG.\n\n" +
"Naming means the rule_id appears verbatim OR a clear substring of the rule description appears. Silent aggregation into a generic bucket like \x27auth churn\x27 / \x27session activity\x27 / \x27routine FIM\x27 is NOT acceptable for rules covered by 1-3 above.\n\n" +
"If no issues, return EXACTLY \x27OK\x27. Otherwise return a bulleted markdown list, one bullet per issue, terse. Do not write anything else.";

return [{ json: {
  model: "claude-sonnet-4-6",
  max_tokens: 512,
  system,
  messages: [{ role: "user", content: userMsg }]
}}];

// Read verifier output. If 'OK', pass through original draft unchanged.
// Else prepend a warn block listing discrepancies, then the draft.
// Output shape mirrors Anthropic response so Format for Telegram works unchanged.
const vresp = $input.first().json;
const verifierText = ((vresp.content && vresp.content[0] && vresp.content[0].text) || '').trim();

const draftResp = $('Anthropic Claude').item.json;
const draftText = (draftResp.content && draftResp.content[0] && draftResp.content[0].text) || '';

const ok = /^OK\.?$/i.test(verifierText);
const finalText = ok
  ? draftText
  : `\u26a0\ufe0f *Verifier flagged:*\n${verifierText}\n\n---\n\n${draftText}`;

return [{ json: {
  content: [{ type: 'text', text: finalText }],
}}];
